1	\chapter{Uniform Mordell--Lang bounds}
2	\label{chap:main}
3	
4	% archon:covers MR4276287UniformityInMordellLangForCurves.lean
5	
6	This chapter derives the uniform bounds on rational points and torsion packets
7	from the geometric and height estimates established earlier.
8	
9	\begin{proposition}[Pre-Mazur bound]
10	  \label{prop:premazur}
11	  \lean{MR4276287UniformityInMordellLangForCurves.preMazur}
12	  \uses{thm:ht_inequality_full,thm:nondeg_for_bd,lem:vojtamumford,prop:alg_pt_far}
13	  % SOURCE: Section 8 of the paper (read from references/MR4276287-mordell-lang-curves-source/RatPt.tex)
14	  % SOURCE QUOTE: "The exist constants \(c_1\ge 0,c_2\ge 1\) ... \(\# (\mathfrak{C}_s(\IQbar)-P_0)\cap \Gamma \le c_2^{1+\rho}\)."
15	  \textit{Source: Section 8 of the paper.}
16	  The proof fixes the moduli point, transfers the sparse-point statement to the
17	  corresponding curve in its Jacobian, and then splits the points into the large
18	  part controlled by Vojta--Mumford and the residual part controlled by the
19	  packet-counting and sparse-points lemmas.
20	\end{proposition}
21	
22	\begin{theorem}[Uniformity in Mordell--Lang for rational points]
23	  \label{thm:bd_rat_intro}
24	  \lean{MR4276287UniformityInMordellLangForCurves.thmBdRatIntro}
25	  \uses{thm:bd_fin_rank,lem:moduli_height_comparison}
26	  % SOURCE: Introduction of the paper (read from references/MR4276287-mordell-lang-curves-source/intro.tex)
27	  % SOURCE QUOTE: "Let \(g \ge 2\) and \(d \ge 1\) be integers. Then there exists a constant \(c = c(g, d) \ge 1\) with the following property. If \(C\) is a smooth curve of genus \(g\) defined over a number field \(F\) with \([F:\IQ] \le d\), then \(\#C(F) \le c^{1+\rho}\)."
28	  \textit{Source: Introduction of the paper.}
29	  The finite-rank theorem supplies the exponential-in-rank estimate once the
30	  Jacobian height is large enough. The moduli-height comparison converts the
31	  bounded-degree number-field hypothesis into a uniform lower bound on the
32	  relevant moduli height, so the constants depend only on \(g\) and \(d\).
33	\end{theorem}
34	
35	\begin{theorem}[Finite-rank Mordell--Lang bound]
36	  \label{thm:bd_fin_rank}
37	  \lean{MR4276287UniformityInMordellLangForCurves.thmBdFinRank}
38	  \uses{prop:premazur,lem:moduli_height_comparison}
39	  % SOURCE: Introduction of the paper (read from references/MR4276287-mordell-lang-curves-source/intro.tex)
40	  % SOURCE QUOTE: "Let \(g \ge 2\) and let \(\iota\) be as above. Then there exist two constants \(c_1= c_1(g,\iota) \ge 0\) and \(c_2 = c_2(g,\iota) \ge 1\) with the following property."
41	  \textit{Source: Introduction of the paper.}
42	  The proof uses the pre-Mazur proposition on the specific curve obtained from
43	  the Jacobian at the moduli point, then compares the Jacobian height with the
44	  projective height of the moduli point to remove any dependence on the curve
45	  beyond the large-height threshold.
46	\end{theorem}
47	
48	\begin{theorem}[Uniform torsion packets]
49	  \label{thm:bd_tor_intro_nf}
50	  \lean{MR4276287UniformityInMordellLangForCurves.thmBdTorIntroNF}
51	  \uses{thm:bd_fin_rank,lem:moduli_height_comparison}
52	  % SOURCE: Introduction of the paper (read from references/MR4276287-mordell-lang-curves-source/intro.tex)
53	  % SOURCE QUOTE: "Let \(g \ge 2\) and \(d \ge 1\) be integers. Then there exists a constant \(c = c(g, d) \ge 1\) with the following property. Let \(C\) be a smooth curve of genus \(g\) defined over a number field \(F\subset\IQbar\) with \([F:\IQ] \le d\) and let \(P_0 \in C(\IQbar)\), then \(\# (C(\overline \IQ)-P_0) \cap \mathrm{Jac}(C)(\IQbar)_{\mathrm{tors}} \le c\)."
54	  \textit{Source: Introduction of the paper.}
55	  This is the rank-zero specialization of the finite-rank theorem, combined with
56	  the same moduli-height comparison used for rational points. The base point
57	  disappears because torsion is a translate-invariant rank-zero subgroup.
58	\end{theorem}
