1	\chapter{Geometric and height infrastructure}
2	\label{chap:basic}
3	
4	% archon:covers MR4276287UniformityInMordellLangForCurves/Basic.lean
5	
6	This chapter packages the geometric and height-theoretic input used by the
7	later counting arguments.
8	
9	\section{Ambient setup}
10	
11	\begin{definition}[Ambient moduli and height data]
12	  \label{def:ambient_setup}
13	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.ambientSetup}
14	  % SOURCE: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
15	  % SOURCE QUOTE: "There exists a universal curve $\mathfrak{C}_g$ over $\mathbb{M}_g$,  it is smooth and proper over $\mathbb{M}_g$ and its fibers are smooth curves of genus $g$."
16	  % SOURCE QUOTE PROOF: This section fixes the universal curve, the universal abelian variety, and the height package used throughout the chapter.
17	  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex).}
18	  Fix \(g \ge 2\). Let \(\mathbb{M}_g\) be the fine moduli space of smooth
19	  genus-\(g\) curves with level structure, let \(\mathfrak{C}_g \to \mathbb{M}_g\)
20	  be the universal curve, and let \(\mathfrak{A}_g \to \mathbb{A}_g\) be the
21	  universal principally polarized abelian variety with the chosen projective
22	  embeddings. Fix the ample line bundles and the associated height functions on
23	  the compactifications, together with the fiberwise Néron--Tate height on the
24	  universal abelian family.
25	\end{definition}
26	
27	\begin{lemma}[Height comparison on the moduli side]
28	  \label{lem:moduli_height_comparison}
29	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.moduliHeightComparison}
30	  \uses{def:ambient_setup}
31	  % SOURCE: Introduction of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/intro.tex)
32	  % SOURCE QUOTE: "If $k=\IQbar$ and as described in $\mathsection\ref{SubsectionHeight}$ we obtain two height functions, the restriction of the Weil height $h\colon \overline{S}(\IQbar)\rightarrow \IR$ and the N\'eron--Tate height $\hat h_{\cA} \colon \cA(\IQbar)\rightarrow \IR$."
33	  % SOURCE QUOTE PROOF: The paper compares these heights after fixing a projective embedding on the moduli side and reading the induced height along the Torelli map.
34	  \textit{Source: Introduction of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/intro.tex).}
35	  The chosen projective height on the moduli space and the height induced by
36	  \(\mathbb{A}_g\) are comparable up to affine linear error terms along the
37	  Torelli map.
38	\end{lemma}
39	
40	\section{Betti geometry}
41	
42	\begin{proposition}[Betti map for the universal abelian variety]
43	  \label{prop:betti_map}
44	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.bettiMap}
45	  \uses{def:ambient_setup}
46	  % SOURCE: Section 2 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/BettiMapForm.tex)
47	  % SOURCE QUOTE: "There exist an open neighborhood \(\Delta\) of \(s_0\) in \(S^{\mathrm{an}}\), and a map \(b_{\Delta}\colon \cA_{\Delta} := \pi^{-1}(\Delta) \rightarrow \mathbb T^{2g}\), called the Betti map, with the following properties."
48	  % SOURCE QUOTE PROOF: This is the local Betti-map construction on the universal abelian family.
49	  \textit{Source: Section 2 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/BettiMapForm.tex).}
50	  Locally on the base, the analytic family of abelian varieties admits a Betti
51	  map to \(\mathbb{T}^{2g}\) whose restriction to each fiber is a group
52	  isomorphism, whose fibers are complex-analytic, and whose product with the
53	  projection to the base is a real-analytic isomorphism.
54	\end{proposition}
55	
56	\begin{proposition}[Betti form]
57	  \label{prop:betti_form}
58	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.bettiForm}
59	  \uses{prop:betti_map}
60	  % SOURCE: Section 2 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/BettiMapForm.tex)
61	  % SOURCE QUOTE: "There exists a closed \((1,1)\)-form \(\omega\) on \(\an{\cA}\), called the Betti form, such that the following properties hold."
62	  % SOURCE QUOTE PROOF: This is the companion form attached to the same universal family, and it controls Betti rank through positivity.
63	  \textit{Source: Section 2 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/BettiMapForm.tex).}
64	  There is a closed semi-positive \((1,1)\)-form on the analytification of the
65	  universal family which scales by \(N^2\) under multiplication-by-\(N\), and
66	  whose top wedge detects the maximal real rank of the Betti map on smooth
67	  loci.
68	\end{proposition}
69	
70	\begin{proposition}[Betti map without the level-structure restrictions]
71	  \label{prop:betti_map_app}
72	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.bettiMapApp}
73	  \uses{def:ambient_setup}
74	  % SOURCE: Appendix B of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneqFinalVer.tex)
75	  % SOURCE QUOTE: "Let \(s_0 \in S(\IC)\). Then there exist an open neighborhood \(\Delta\) of \(s_0\) in \(S^{\mathrm{an}}\), and a map \(b_{\Delta} \colon \cA_{\Delta} := \pi^{-1}(\Delta) \rightarrow \mathbb T^{2g}\), called the Betti map, with the following properties."
76	  % SOURCE QUOTE PROOF: The appendix repeats the Betti-map construction after passing to a finite étale cover when needed.
77	  \textit{Source: Appendix B of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneqFinalVer.tex).}
78	  The local Betti-map construction persists for arbitrary regular bases and
79	  abelian schemes after passing to a finite étale cover when necessary.
80	\end{proposition}
81	
82	\begin{lemma}[Betti rank is insensitive to shrinking the base]
83	  \label{lem:betti_rank_zar_open_app}
84	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.bettiRankZarOpen}
85	  \uses{prop:betti_map_app}
86	  % SOURCE: Appendix B of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneqFinalVer.tex)
87	  % SOURCE QUOTE: "Let \(b_{\Delta} \colon \cA_{\Delta} \rightarrow \mathbb T^{2g}\) be a Betti map as in Proposition~\ref{PropBettiMapApp}. Let \(X\) be an irreducible subvariety of \(\cA\) with \(\an{X}\cap\cA_\Delta\not=\emptyset\). Let \(U\) be a Zariski open dense subset of \(X\). Then ... the maximum rank is the same on \(X\) and on \(U\)."
88	  % SOURCE QUOTE PROOF: The same local rank is attained on a dense open subset because rank is locally constant where it is maximal.
89	  \textit{Source: Appendix B of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneqFinalVer.tex).}
90	  Passing to a Zariski open dense subset does not change the maximal Betti-map
91	  rank seen on the smooth locus.
92	\end{lemma}
93	
94	\begin{lemma}[Silverman--Tate height comparison]
95	  \label{thm:silverman_tate}
96	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.silvermanTate}
97	  \uses{def:ambient_setup}
98	  % SOURCE: Appendix A of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/silvermantate.tex)
99	  % SOURCE QUOTE: "There exists a constant \(c>0\) such that for all \(P \in \cA(\IQbar)\) we have \(\bigl| \hat h_{\cA}(P) - \hcA(P)\bigr| \le c \max\{1,h_{\overline S}(\pi(P))\}.\)"
100	  % SOURCE QUOTE PROOF: The comparison is the canonical-height versus projective-height estimate used to move between the fiber and the base.
101	  \textit{Source: Appendix A of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/silvermantate.tex).}
102	  The canonical height on a fiber differs from the naive projective height by an
103	  error bounded linearly in the height of the base point.
104	\end{lemma}
105	
106	\section{Height inequality}
107	
108	\begin{definition}[Non-degenerate subvariety]
109	  \label{def:nondegenerate_app}
110	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.nonDegenerate}
111	  \uses{prop:betti_map_app}
112	  % SOURCE: Appendix B of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneqFinalVer.tex)
113	  % SOURCE QUOTE: "An irreducible subvariety \(X\) of \(\cA\) is said to be non-degenerate if there exists an open non-empty subset \(\Delta\) ... such that ... \(\max_{x \in X^{\mathrm{sm}}(\IC) \cap \cA_{\Delta}} \mathrm{rank}_{\IR} (\mathrm{d}b_{\Delta}|_{X^{\mathrm{sm,an}}})_x = 2\dim X\)."
114	  % SOURCE QUOTE PROOF: This restates the appendix criterion in the language of local Betti rank on the smooth locus.
115	  \textit{Source: Appendix B of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneqFinalVer.tex).}
116	  An irreducible subvariety is non-degenerate if some local Betti map has full
117	  real rank \(2\dim X\) on a smooth point of the analytification.
118	\end{definition}
119	
120	\begin{proposition}[Auxiliary height inequality]
121	  \label{prop:aux_ht_ineq}
122	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.auxHeightInequality}
123	  \uses{prop:betti_form,thm:silverman_tate,def:nondegenerate_app,lem:graph_construction}
124	  % SOURCE: Section 4 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneq.tex)
125	  % SOURCE QUOTE: "Suppose \(\an{X}\) contains a smooth point at which \(\omega|_{\sman{X}}^{\wedge d} >0\). Then there exists a constant \(c_1 > 0\) ... \(h([N]P) \ge c_1 N^2 h(\pi(P)) - c_2(N)\)."
126	  % SOURCE QUOTE PROOF: The proof studies the graph of multiplication-by-\(N\), uses the Betti form to force positivity there, and then reads off a height lower bound.
127	  \textit{Source: Section 4 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneq.tex).}
128	  The graph construction turns the estimate into a comparison of intersection
129	  numbers on the projective closure \(\overline{X_N}\). Siu's criterion then
130	  converts the positivity of the Betti form into a lower bound for the
131	  projective height of \([N]P\) in terms of the height of the base point.
132	\end{proposition}
133	
134	\begin{lemma}[Graph construction for the height inequality]
135	  \label{lem:graph_construction}
136	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.graphConstruction}
137	  \uses{def:ambient_setup}
138	  % SOURCE: Section 4 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneq.tex)
139	  % SOURCE QUOTE: "For each \(N \in \IN\), we work with \(X_N \subseteq \cA\times_S \cA\), the graph of \([N] \colon \cA \rightarrow \cA\), and its Zariski closure \(\overline{X_N}\) in \(\overline{\cA}\times_{\overline{S}}\overline{\cA}\)."
140	  % SOURCE QUOTE PROOF: This is the projective closure on which the auxiliary inequality is evaluated.
141	  \textit{Source: Section 4 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneq.tex).}
142	  For each \(N\), the graph of multiplication-by-\(N\) on the family produces a
143	  projective closure \(\overline{X_N}\) on which the relevant heights become the
144	  heights associated to the line bundles \(\mathcal F\) and \(\mathcal M\).
145	\end{lemma}
146	
147	\begin{theorem}[Height inequality under the paper's hypotheses]
148	  \label{thm:ht_inequality}
149	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.heightInequality}
150	  \uses{prop:aux_ht_ineq,thm:silverman_tate,lem:graph_construction}
151	  % SOURCE: Section 5 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/NTbase.tex)
152	  % SOURCE QUOTE: "There exists a constant \(c_1>0\) ... \(\hat{h}_{\mathcal{A}}(P) \ge c_1 N^2 h(\pi(P)) - c_2(N)\)."
153	  % SOURCE QUOTE PROOF: This is the canonical-height form of the auxiliary estimate after the Silverman--Tate comparison is inserted.
154	  \textit{Source: Section 5 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/NTbase.tex).}
155	  After one fixed power of \(2\) is chosen, the canonical height on the total
156	  space is bounded below by a positive multiple of the height on the base on a
157	  dense open subset of any non-degenerate subvariety.
158	\end{theorem}
159	
160	\begin{theorem}[Full height inequality]
161	  \label{thm:ht_inequality_full}
162	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.heightInequalityFull}
163	  \uses{prop:betti_map_app,lem:betti_rank_zar_open_app,def:nondegenerate_app,thm:ht_inequality}
164	  % SOURCE: Appendix B of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneqFinalVer.tex)
165	  % SOURCE QUOTE: "Let \(X\) be an irreducible subvariety of \(\cA\) ... Then there exist constants \(c_1>0\) and \(c_2\ge 0\) and a Zariski open dense subset \(U\) of \(X\) with \(\hat{h}_{\cA,\cL}(P) \ge c_1 h_{\overline{S},\cM}( \pi(P) ) - c_2\)."
166	  % SOURCE QUOTE PROOF: The appendix removes the extra Hyp assumptions by passing through the general Betti-map setup and then shrinking to a dense open subset.
167	  \textit{Source: Appendix B of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneqFinalVer.tex).}
168	  The appendix first enlarges the Betti-map input to arbitrary regular bases and
169	  then performs a six-step devissage: close up \(X\), replace the base by the
170	  image of \(X\), pass to a regular cover carrying level structure and a
171	  principal polarization, and finally invoke the height inequality already
172	  proved under the paper's hypotheses. The result is the same lower bound for
173	  the canonical height on a dense open subset of any non-degenerate subvariety.
174	\end{theorem}
175	
176	\section{Counting lemmas}
177	
178	\begin{lemma}[Uniform degree bound]
179	  \label{lem:uniform_degree_bound}
180	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.uniformDegreeBound}
181	  \uses{def:ambient_setup}
182	  % SOURCE: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
183	  % SOURCE QUOTE: "There exists a constant \(c\) such that ... \(\deg(\mathfrak{C}_s-P) \le c\) ... and \(h(\mathfrak{C}_s-P_s) \le c \max\{1, h_{\overline{\mathbb{A}_g},\cM}(\tau(s))\}\)."
184	  % SOURCE QUOTE PROOF: The section bounds both the projective degree and the moduli height of the translated fibers uniformly in the base point.
185	  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex).}
186	  Translates of a fixed fiber curve have uniformly bounded projective degree, and
187	  one translate in each fiber has height controlled by the moduli point.
188	\end{lemma}
189	
190	\begin{theorem}[Non-degeneracy of the Faltings--Zhang image]
191	  \label{thm:nondeg_for_bd}
192	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.faltingsZhangNondegenerate}
193	  \uses{def:ambient_setup,def:nondegenerate_app}
194	  % SOURCE: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
195	  % SOURCE QUOTE: "Let \(S\) be an irreducible variety with a (not necessarily dominant) quasi-finite morphism \(S \rightarrow \mathbb{M}_g\). Assume \(g \ge 2\) and \(M \ge 3g-2\). Then \(\mathscr{D}_M( \mathfrak{C}_S^{[M+1]} )\) ... is non-degenerate."
196	  % SOURCE QUOTE PROOF: Gao's theorem gives the needed non-degeneracy once the fiber power is large enough.
197	  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex).}
198	  For sufficiently large fiber power, Gao's theorem shows that the Faltings--Zhang
199	  image of the universal curve family is non-degenerate.
200	\end{theorem}
201	
202	\begin{lemma}[Quantitative Vojta--Mumford estimate]
203	  \label{lem:vojtamumford}
204	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.vojtaMumford}
205	  \uses{thm:silverman_tate,lem:uniform_degree_bound}
206	  % SOURCE: Section 8 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/RatPt.tex)
207	  % SOURCE QUOTE: "Let \(C\) be an irreducible curve in \(A\). There exists a constant \(c=c(n,\deg C)\ge 1\) ... \# \{P \in C(\IQbar)\cap \Gamma : \hat h_{L}(P) > c\max\{1,h(C),c_{\mathrm{NT}},h_1\} \} \le c^\rho."
208	  % SOURCE QUOTE PROOF: The estimate is the large-points part of the Vojta--Mumford method and depends on the subgroup rank through the exponent.
209	  \textit{Source: Section 8 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/RatPt.tex).}
210	  A curve inside an abelian variety contributes at most exponentially many points
211	  of large canonical height, with the exponent controlled by the subgroup rank.
212	\end{lemma}
213	
214	\begin{lemma}[N-Alon combinatorial lemma]
215	  \label{lem:NAlon}
216	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.nAlon}
217	  \uses{def:ambient_setup}
218	  % SOURCE: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
219	  % SOURCE QUOTE: "Let \(C \subset \IP_k^n\) be an irreducible curve ... Then there exists a number \(B\), depending only on \(M, \deg C,\) and \(\deg Z\), ... if \(\Sigma \subset C(k)\) has cardinality \(\ge B\), then \(\Sigma^M \not\subseteq Z(k)\)."
220	  % SOURCE QUOTE PROOF: This is the product-avoidance input used to keep large subsets of a curve from collapsing into a proper closed set.
221	  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex).}
222	  Large enough subsets of a curve cannot have all \(M\)-fold products trapped in
223	  a fixed proper closed subset of the ambient product.
224	\end{lemma}
225	
226	\begin{lemma}[Packets alternative]
227	  \label{lem:packets_alternative3}
228	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.packetsAlternative}
229	  \uses{def:ambient_setup}
230	  % SOURCE: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
